#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long A,B,K; scanf("%lld %lld %lld", &A, &B, &K);
        long long diff = llabs(A - B);
        long long steps = (diff + K - 1) / K;
        printf("%lld\n", steps);
    }
    return 0;
}

